def now_madrid():
    """Devuelve datetime actual en hora de España (UTC+1/UTC+2)"""
    import time as _time
    utc_now = datetime.utcnow()
    # Determinar si estamos en horario de verano (último domingo de marzo a último domingo de octubre)
    year = utc_now.year
    # Último domingo de marzo
    march_last_sunday = max(d for d in range(25, 32) if datetime(year, 3, d).weekday() == 6)
    # Último domingo de octubre
    oct_last_sunday = max(d for d in range(25, 32) if datetime(year, 10, d).weekday() == 6)
    dst_start = datetime(year, 3, march_last_sunday, 1, 0)  # 01:00 UTC
    dst_end   = datetime(year, 10, oct_last_sunday, 1, 0)   # 01:00 UTC
    offset = timedelta(hours=2) if dst_start <= utc_now < dst_end else timedelta(hours=1)
    return utc_now + offset

