@app.route("/api/manipulado/estado", methods=["POST"])
def manipulado_estado():
    try:
        data = request.get_json()
        service = get_sheets_service()
        row_num = int(data.get("row"))
        estado = str(data.get("estado", ""))
        updates = []

        # Solo actualizar estado si viene
        if estado:
            updates.append({"range": f"{MANIPULADO_SHEET}!I{row_num}", "values": [[estado]]})

        # Inicio - solo escribir si viene y es en_curso
        if estado == "en_curso" and data.get("inicio"):
            updates.append({"range": f"{MANIPULADO_SHEET}!J{row_num}", "values": [[data["inicio"]]]})

        # Finalizado - escribir fin y minutos pero NO tocar inicio
        if estado == "finalizado":
            if data.get("fin"):
                updates.append({"range": f"{MANIPULADO_SHEET}!K{row_num}", "values": [[data["fin"]]]})
            if data.get("minutos") is not None:
                updates.append({"range": f"{MANIPULADO_SHEET}!L{row_num}", "values": [[str(data["minutos"])]]})

        # Palet
        if data.get("palet") is not None and data.get("palet") != "":
            updates.append({"range": f"{MANIPULADO_SHEET}!F{row_num}", "values": [[str(data["palet"])]]})

        # Lote
        if data.get("lote"):
            updates.append({"range": f"{MANIPULADO_SHEET}!O{row_num}", "values": [[str(data["lote"])]]})

        # Personas (puede ser decimal ponderado, ej: 11.2)
        if data.get("personas") is not None and str(data.get("personas","")) != "":
            try:
                pers_val = round(float(data["personas"]), 1)
            except:
                pers_val = data["personas"]
            updates.append({"range": f"{MANIPULADO_SHEET}!M{row_num}", "values": [[pers_val]]})

        # Observaciones
        if data.get("observaciones"):
            updates.append({"range": f"{MANIPULADO_SHEET}!N{row_num}", "values": [[str(data["observaciones"])]]})

        if updates:
            service.spreadsheets().values().batchUpdate(
                spreadsheetId=SHEET_ID,
                body={"valueInputOption": "RAW", "data": updates}
            ).execute()
        return jsonify({"ok": True})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})



