# STOCK
# Hoja "Stock": Albaran|Fecha|Proveedor|Producto|TCult|Origen|Palets|Bultos|KgBrutos|KgNetos|FechaImport
# ═══════════════════════════════════════════════════════
STOCK_SHEET = "Stock"

@app.route("/api/stock/importar", methods=["POST"])
def stock_importar():
    """Importa CSV de Orizon a hoja Stock"""
    try:
        if 'csv' not in request.files:
            return jsonify({"ok": False, "error": "No se recibio CSV"})

        file = request.files['csv']
        raw = file.read()

        # Encoding: latin-1 primero para CSVs españoles (Orizon)
        for enc_try in ['latin-1', 'utf-8-sig', 'utf-8', 'cp1252']:
            try:
                text = raw.decode(enc_try)
                break
            except:
                continue
        else:
            text = raw.decode('latin-1', errors='replace')

        lines = text.strip().replace('\r\n','\n').replace('\r','\n').split('\n')
        if len(lines) < 2:
            return jsonify({"ok": False, "error": "CSV vacío"})

        # Parsear - columnas: Serie-Albarán;Fecha;Proveedor;Genero;Tipo cultivo;Origen;Num.Palets;Bultos;KgBrutos;KgNetos
        fecha_import = now_madrid().strftime('%d/%m/%Y')
        filas = []
        for line in lines[1:]:
            if not line.strip(): continue
            parts = line.split(';')
            if len(parts) < 10: continue
            albaran  = parts[0].strip()
            fecha    = parts[1].strip()
            prov     = parts[2].strip()
            prod     = parts[3].strip().upper()
            tcult    = parts[4].strip().upper()
            origen   = parts[5].strip()
            palets   = parts[6].strip().replace(',','.')
            bultos   = parts[7].strip()
            kg_brut  = parts[8].strip().replace(',','.')
            kg_neto  = parts[9].strip().replace(',','.')
            filas.append([albaran, fecha, prov, prod, tcult, origen, palets, bultos, kg_brut, kg_neto, fecha_import])

        if not filas:
            return jsonify({"ok": False, "error": "No se encontraron filas válidas"})

        service = get_sheets_service()

        # Crear hoja Stock si no existe
        meta = service.spreadsheets().get(spreadsheetId=SHEET_ID).execute()
        sheet_names = [s['properties']['title'] for s in meta.get('sheets',[])]
        if STOCK_SHEET not in sheet_names:
            service.spreadsheets().batchUpdate(spreadsheetId=SHEET_ID, body={
                "requests": [{"addSheet": {"properties": {"title": STOCK_SHEET}}}]
            }).execute()
            # Cabecera
            service.spreadsheets().values().update(
                spreadsheetId=SHEET_ID, range=f"{STOCK_SHEET}!A1",
                valueInputOption="RAW",
                body={"values": [["Albaran","Fecha","Proveedor","Producto","TCult","Origen","Palets","Bultos","KgBrutos","KgNetos","FechaImport"]]}
            ).execute()

        # Evitar duplicados: borrar filas con misma fecha de entrada
        fecha_csv = filas[0][1] if filas else ''
        if fecha_csv:
            existing = service.spreadsheets().values().get(
                spreadsheetId=SHEET_ID, range=f"{STOCK_SHEET}!A:B"
            ).execute().get('values', [])
            filas_borrar = [i+1 for i,r in enumerate(existing) if i>0 and len(r)>1 and r[1].strip()==fecha_csv]
            if filas_borrar:
                sid = get_sheet_id(service, SHEET_ID, STOCK_SHEET)
                reqs = [{"deleteDimension": {"range": {
                    "sheetId": sid, "dimension": "ROWS",
                    "startIndex": f-1, "endIndex": f
                }}} for f in sorted(filas_borrar, reverse=True)]
                service.spreadsheets().batchUpdate(spreadsheetId=SHEET_ID, body={"requests": reqs}).execute()

        service.spreadsheets().values().append(
            spreadsheetId=SHEET_ID, range=f"{STOCK_SHEET}!A1",
            valueInputOption="RAW", insertDataOption="INSERT_ROWS",
            body={"values": filas}
        ).execute()

        return jsonify({"ok": True, "importadas": len(filas), "fecha": fecha_csv})

    except Exception as e:
        import traceback
        return jsonify({"ok": False, "error": str(e), "trace": traceback.format_exc()[-1000:]})


@app.route("/api/stock")
def api_stock():
    """Calcula stock disponible = entradas - confeccionado - destrío"""
    try:
        service = get_sheets_service()

        # ── Leer hoja Stock ──
        res = service.spreadsheets().values().get(
            spreadsheetId=SHEET_ID, range=f"{STOCK_SHEET}!A:K"
        ).execute()
        rows_stock = res.get('values', [])
        if len(rows_stock) <= 1:
            return jsonify({"ok": True, "resumen": [], "entradas": [], "vs_pedidos": [], "fecha_ultima": ""})

        hoy = now_madrid().date()

        def parse_fecha(s):
            try:
                return datetime.strptime(s.strip(), '%d/%m/%Y').date()
            except:
                return None

        def to_f(s):
            try: return float(str(s).replace(',','.').strip())
            except: return 0.0

        # Construir entradas con kg disponible inicial = kg_neto
        entradas = []
        for r in rows_stock[1:]:
            if len(r) < 10: continue
            albaran = r[0].strip()
            fecha   = parse_fecha(r[1])
            prov    = r[2].strip()
            prod    = r[3].strip().upper()
            tcult   = r[4].strip()
            palets  = to_f(r[6])
            kg_neto = to_f(r[9])
            if not fecha or kg_neto <= 0: continue
            dias = (hoy - fecha).days
            entradas.append({
                'albaran':   albaran,
                'fecha':     r[1].strip(),
                'fecha_dt':  fecha,
                'proveedor': prov,
                'producto':  prod,
                'tcult':     tcult,
                'palets':    palets,
                'kg_entrado':kg_neto,
                'kg_disponible': kg_neto,  # se descontará abajo
                'dias_en_stock': dias,
            })

        # ── Leer manipulado para descontar kg usados ──
        try:
            res_man = service.spreadsheets().values().get(
                spreadsheetId=SHEET_ID, range="Manipulado!A:O"
            ).execute()
            rows_man = res_man.get('values', [])
            # Columnas: A=ID,B=Fecha,C=Pedido,D=Producto,E=Cliente,F=Palet,G=Bultos,H=Linea,I=Estado,J=Inicio,K=Fin,L=Min,M=Personas,N=Obs,O=Lote
            kg_usado_por_prod = {}
            for r in rows_man[1:]:
                if len(r) < 9: continue
                if r[8].strip() not in ('finalizado','en_curso'): continue
                prod_man = r[3].strip().upper() if len(r)>3 else ''
                # Buscar kg en hoja Pedidos para este pedido+producto
                # Por ahora usamos bultos*kg_por_bulto estimado - simplificado
                # Se mejora en v2 cruzando con Pedidos
                pass
        except: pass

        # ── Leer destrío desde hoja Manipulado col N (obs con kg_destrio) ──
        # El destrío está en /api/guardar-lote con tipo=destrio
        # Leer hoja Estado para destríos
        kg_destrio_por_prod = {}
        try:
            res_est = service.spreadsheets().values().get(
                spreadsheetId=SHEET_ID, range="Estado!A:D"
            ).execute()
            import json as _json2
            for r in res_est.get('values',[])[1:]:
                if len(r) < 4: continue
                if r[2].strip() == 'destrio':
                    try:
                        d_data = _json2.loads(r[3])
                        prod_d = str(d_data.get('producto','')).upper().strip()
                        kg_d   = to_f(d_data.get('kg',0))
                        if prod_d and kg_d > 0:
                            kg_destrio_por_prod[prod_d] = kg_destrio_por_prod.get(prod_d, 0) + kg_d
                    except: pass
        except: pass

        # ── Cruzar con Pedidos para "vs_pedidos" ──
        kg_pedidos_por_prod = {}
        fecha_ultima = ''
        try:
            res_ped = service.spreadsheets().values().get(
                spreadsheetId=SHEET_ID, range="Pedidos!A:Z"
            ).execute()
            rows_ped = res_ped.get('values', [])
            if rows_ped:
                hdrs = [str(h).strip().lower() for h in rows_ped[0]]
                def ci(names):
                    for n in names:
                        for i,h in enumerate(hdrs):
                            if n in h: return i
                    return None
                ci_prod   = ci(['producto','presentac'])
                ci_kilos  = ci(['kilos','kg'])
                ci_fecha  = ci(['salida','fecha'])
                if ci_prod and ci_kilos:
                    for r in rows_ped[1:]:
                        prod_p = r[ci_prod].strip().upper() if ci_prod<len(r) else ''
                        kg_p   = to_f(r[ci_kilos]) if ci_kilos and ci_kilos<len(r) else 0
                        # Solo pedidos de los próximos 7 días
                        if ci_fecha and ci_fecha<len(r):
                            fd = parse_fecha(r[ci_fecha])
                            if fd and 0 <= (fd-hoy).days <= 7:
                                if prod_p and kg_p>0:
                                    kg_pedidos_por_prod[prod_p] = kg_pedidos_por_prod.get(prod_p,0)+kg_p
        except: pass

        # ── Construir resumen por producto ──
        from collections import defaultdict
        resumen = defaultdict(lambda: {
            'kg_entrado':0,'kg_disponible':0,'kg_usado':0,'kg_destrio':0,
            'palets_disponibles':0,'dias_max_entrada':0,'fecha_entrada_max':'','tcult':''
        })

        for e in entradas:
            p = e['producto']
            r = resumen[p]
            destrio_prod = kg_destrio_por_prod.get(p, 0)
            # Distribuir destrío proporcionalmente (simplificado: al producto)
            r['kg_entrado']        += e['kg_entrado']
            r['kg_destrio']         = destrio_prod
            r['palets_disponibles'] += e['palets']
            r['tcult']              = e['tcult']
            if e['dias_en_stock'] > r['dias_max_entrada']:
                r['dias_max_entrada'] = e['dias_en_stock']
                r['fecha_entrada_max'] = e['fecha']
            # Actualizar fecha última
            if not fecha_ultima or e['fecha_dt'] > parse_fecha(fecha_ultima):
                fecha_ultima = e['fecha']

        # Calcular disponible = entrado - destrío (manipulado se añadirá en v2)
        resumen_list = []
        for prod, r in resumen.items():
            r['producto']       = prod
            r['kg_disponible']  = max(0, r['kg_entrado'] - r['kg_destrio'] - r.get('kg_usado',0))
            resumen_list.append(r)

        resumen_list.sort(key=lambda x: -x['kg_disponible'])

        # ── vs_pedidos ──
        vs_pedidos = []
        for prod, kg_nec in kg_pedidos_por_prod.items():
            kg_disp = next((r['kg_disponible'] for r in resumen_list if r['producto']==prod), 0)
            vs_pedidos.append({
                'producto': prod,
                'kg_necesario': round(kg_nec,1),
                'kg_disponible': round(kg_disp,1),
            })
        vs_pedidos.sort(key=lambda x: x['kg_disponible']-x['kg_necesario'])

        return jsonify({
            "ok": True,
            "resumen": resumen_list,
            "entradas": sorted(entradas, key=lambda x: x['dias_en_stock'], reverse=True),
            "vs_pedidos": vs_pedidos,
            "fecha_ultima": fecha_ultima,
        })

    except Exception as e:
        import traceback
        return jsonify({"ok": False, "error": str(e), "trace": traceback.format_exc()})

@app.route("/api/manipulado/eliminar", methods=["POST"])
def manipulado_eliminar():
    try:
        data = request.get_json()
        service = get_sheets_service()
        row_num = int(data.get("row"))
        service.spreadsheets().values().update(
            spreadsheetId=SHEET_ID,
            range=f"{MANIPULADO_SHEET}!I{row_num}",
            valueInputOption="RAW",
            body={"values": [["anulado"]]}
        ).execute()
        return jsonify({"ok": True})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})


def ensure_stock_sheet():
    """Crea la hoja Stock si no existe al arrancar"""
    try:
        service = get_sheets_service()
        meta = service.spreadsheets().get(spreadsheetId=SHEET_ID).execute()
        sheet_names = [s['properties']['title'] for s in meta.get('sheets',[])]
        if 'Stock' not in sheet_names:
            service.spreadsheets().batchUpdate(spreadsheetId=SHEET_ID, body={
                "requests": [{"addSheet": {"properties": {"title": "Stock"}}}]
            }).execute()
            service.spreadsheets().values().update(
                spreadsheetId=SHEET_ID, range="Stock!A1",
                valueInputOption="RAW",
                body={"values": [["Albaran","Fecha","Proveedor","Producto","TCult","Origen","Palets","Bultos","KgBrutos","KgNetos","FechaImport"]]}
            ).execute()
            print("Hoja Stock creada con cabecera")
        else:
            print("Hoja Stock ya existe")
    except Exception as e:
        print(f"Error ensure_stock_sheet: {e}")

if __name__ == "__main__":
    port = int(os.environ.get("PORT", 5000))
    ensure_stock_sheet()
    app.run(host="0.0.0.0", port=port, debug=False)
